        HasSwitches: true,
        key_pgDown: Main_Blocked,
        key_pgUp: Main_UserChannels,
        histPosY: 0,
        emptyContent_STR: function () {
            return STR_HISTORY_EMPTY_CONTENT;
        },
        histPosXTemp: [0, 0, 0, 0],
        sorting: [],
        sortingValues: [
            ['date', 0],
            ['date', 1],
            ['name', 1],
            ['name', 0],
            ['game', 1],
            ['game', 0],
            ['views', 0],
            ['views', 1],
            ['created_at', 0],
            ['created_at', 1]
        ],
        sortingPos: 0,
